import React from 'react';
import { MemoryRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { Provider } from 'react-redux';
import { store } from './store/store';
import { AppLayout } from './components/layout/AppLayout';
import { SimpleNotFoundPage } from '@linm-soft-org/linm-web-common-components';
import { isStandalone, showDevNav } from './dev/isStandalone';
import { StandaloneMockNav } from './standalone/StandaloneMockNav';
import { MemoryRouterSync } from './router/MemoryRouterSync';
import { MH_PATHS, KHO_PATHS } from './appPaths';

const DevPage = React.lazy(() => import('./dev/DevPage'));
const DevSampleDataPage = React.lazy(() => import('./dev/DevSampleDataPage'));

// ── Mua Hàng (mh) ──────────────────────────────────────────────────────────
const YcmhListPage       = React.lazy(() => import('./pages/mh/YcmhListPage'));
const YcmhDetailPage     = React.lazy(() => import('./pages/mh/YcmhDetailPage'));
const YcmhFormPage       = React.lazy(() => import('./pages/mh/YcmhFormPage'));
const DdmhListPage       = React.lazy(() => import('./pages/mh/DdmhListPage'));
const DdmhDetailPage     = React.lazy(() => import('./pages/mh/DdmhDetailPage'));
const DdmhFormPage       = React.lazy(() => import('./pages/mh/DdmhFormPage'));
const PnhListPage        = React.lazy(() => import('./pages/mh/PnhListPage'));
const PnhFormPage        = React.lazy(() => import('./pages/mh/PnhFormPage'));
const HddtPage           = React.lazy(() => import('./pages/mh/HddtPage'));
const ApprovalFlowPage   = React.lazy(() => import('./pages/mh/ApprovalFlowPage'));
const PhanQuyenDuyetPage = React.lazy(() => import('./pages/mh/PhanQuyenDuyetPage'));

// ── Kho / WMS (kho) ─────────────────────────────────────────────────────────
const PnkListPage              = React.lazy(() => import('./pages/kho/PnkListPage'));
const PnkFormPage              = React.lazy(() => import('./pages/kho/PnkFormPage'));
const PnkGiaCongPage           = React.lazy(() => import('./pages/kho/PnkGiaCongPage'));
const PnkCongDoanPage          = React.lazy(() => import('./pages/kho/PnkCongDoanPage'));
const PnkThanhPhamPage         = React.lazy(() => import('./pages/kho/PnkThanhPhamPage'));
const PxkListPage              = React.lazy(() => import('./pages/kho/PxkListPage'));
const PxkFormPage              = React.lazy(() => import('./pages/kho/PxkFormPage'));
const PxkGiaCongPage           = React.lazy(() => import('./pages/kho/PxkGiaCongPage'));
const PxkCongDoanPage          = React.lazy(() => import('./pages/kho/PxkCongDoanPage'));
const PxkThanhPhamPage         = React.lazy(() => import('./pages/kho/PxkThanhPhamPage'));
const KiemKhoPage              = React.lazy(() => import('./pages/kho/KiemKhoPage'));
const DieuChuyenVtPage         = React.lazy(() => import('./pages/kho/DieuChuyenVtPage'));
const DieuChinhKhoPage         = React.lazy(() => import('./pages/kho/DieuChinhKhoPage'));
const XuatThanhLyPage          = React.lazy(() => import('./pages/kho/XuatThanhLyPage'));
const ThanhPhamLoiPage         = React.lazy(() => import('./pages/kho/ThanhPhamLoiPage'));
const TonKhoPage               = React.lazy(() => import('./pages/kho/TonKhoPage'));
const TheKhoPage               = React.lazy(() => import('./pages/kho/TheKhoPage'));
const BaoCaoKhoCongDoanPage    = React.lazy(() => import('./pages/kho/BaoCaoKhoCongDoanPage'));
const BaoCaoThanhPhamLoiPage   = React.lazy(() => import('./pages/kho/BaoCaoThanhPhamLoiPage'));

const p = (path: string) => path.slice(1);

const Suspense = ({ children }: { children: React.ReactNode }) => (
  <React.Suspense fallback={<div style={{ padding: '2rem' }}>Đang tải...</div>}>
    {children}
  </React.Suspense>
);

const AppShell = () => (
  <>
    {isStandalone && <StandaloneMockNav />}
    <AppLayout />
  </>
);

const initialPath =
  typeof window !== 'undefined'
    ? window.location.pathname + window.location.search || '/'
    : '/';

const AppRouter: React.FC = () => (
  <>
    <MemoryRouterSync />
    <Routes>
        <Route path="/" element={isStandalone ? <AppShell /> : <AppLayout />}>
          {showDevNav && (
            <>
              <Route index element={<Navigate to="/dev" replace />} />
              <Route path="dev" element={<Suspense><DevPage /></Suspense>} />
              <Route path={p(KHO_PATHS.devSampleData)} element={<Suspense><DevSampleDataPage /></Suspense>} />
              <Route path="dev/tao-du-lieu-mau" element={<Suspense><DevSampleDataPage /></Suspense>} />
            </>
          )}
          {/* Mua Hàng — MM slugs */}
          <Route path="mh" element={<Navigate to={p(MH_PATHS.ycmh)} replace />} />
          <Route path={p(MH_PATHS.ycmh)}              element={<Suspense><YcmhListPage /></Suspense>} />
          <Route path={p(MH_PATHS.ycmhThem)}           element={<Suspense><YcmhFormPage /></Suspense>} />
          <Route path={`${p(MH_PATHS.ycmh)}/:id`}     element={<Suspense><YcmhDetailPage /></Suspense>} />
          <Route path={p(MH_PATHS.ddmh)}              element={<Suspense><DdmhListPage /></Suspense>} />
          <Route path={p(MH_PATHS.ddmhThem)}           element={<Suspense><DdmhFormPage /></Suspense>} />
          <Route path={`${p(MH_PATHS.ddmh)}/:id`}     element={<Suspense><DdmhDetailPage /></Suspense>} />
          <Route path={p(MH_PATHS.nhanHang)}           element={<Suspense><PnhListPage /></Suspense>} />
          <Route path={p(MH_PATHS.nhanHangThem)}       element={<Suspense><PnhFormPage /></Suspense>} />
          <Route path={`${p(MH_PATHS.nhanHang)}/:id`} element={<Suspense><PnhFormPage /></Suspense>} />
          <Route path={p(MH_PATHS.hddt)}               element={<Suspense><HddtPage /></Suspense>} />
          <Route path={p(MH_PATHS.approvalFlow)}       element={<Suspense><ApprovalFlowPage /></Suspense>} />
          <Route path={p(MH_PATHS.phanQuyenDuyet)}     element={<Suspense><PhanQuyenDuyetPage /></Suspense>} />

          {/* Kho — MM slugs */}
          <Route path="kho" element={<Navigate to={p(KHO_PATHS.pnk)} replace />} />
          <Route path={p(KHO_PATHS.pnk)}                    element={<Suspense><PnkListPage /></Suspense>} />
          <Route path={p(KHO_PATHS.pnkThem)}                element={<Suspense><PnkFormPage /></Suspense>} />
          <Route path={`${p(KHO_PATHS.pnk)}/:id`}           element={<Suspense><PnkFormPage /></Suspense>} />
          <Route path={p(KHO_PATHS.pnkGiaCong)}             element={<Suspense><PnkGiaCongPage /></Suspense>} />
          <Route path={p(KHO_PATHS.pnkCongDoan)}            element={<Suspense><PnkCongDoanPage /></Suspense>} />
          <Route path={p(KHO_PATHS.pnkThanhPham)}           element={<Suspense><PnkThanhPhamPage /></Suspense>} />
          <Route path={p(KHO_PATHS.pxk)}                    element={<Suspense><PxkListPage /></Suspense>} />
          <Route path={p(KHO_PATHS.pxkThem)}                element={<Suspense><PxkFormPage /></Suspense>} />
          <Route path={`${p(KHO_PATHS.pxk)}/:id`}           element={<Suspense><PxkFormPage /></Suspense>} />
          <Route path={p(KHO_PATHS.pxkGiaCong)}             element={<Suspense><PxkGiaCongPage /></Suspense>} />
          <Route path={p(KHO_PATHS.pxkCongDoan)}            element={<Suspense><PxkCongDoanPage /></Suspense>} />
          <Route path={p(KHO_PATHS.pxkThanhPham)}           element={<Suspense><PxkThanhPhamPage /></Suspense>} />
          <Route path={p(KHO_PATHS.kiemKho)}                element={<Suspense><KiemKhoPage /></Suspense>} />
          <Route path={p(KHO_PATHS.dieuChuyenVt)}           element={<Suspense><DieuChuyenVtPage /></Suspense>} />
          <Route path={p(KHO_PATHS.dieuChinhKho)}           element={<Suspense><DieuChinhKhoPage /></Suspense>} />
          <Route path={p(KHO_PATHS.xuatThanhLy)}            element={<Suspense><XuatThanhLyPage /></Suspense>} />
          <Route path={p(KHO_PATHS.thanhPhamLoi)}           element={<Suspense><ThanhPhamLoiPage /></Suspense>} />
          <Route path={p(KHO_PATHS.tonKho)}                 element={<Suspense><TonKhoPage /></Suspense>} />
          <Route path={p(KHO_PATHS.theKho)}                 element={<Suspense><TheKhoPage /></Suspense>} />
          <Route path={p(KHO_PATHS.baoCaoKhoCongDoan)}      element={<Suspense><BaoCaoKhoCongDoanPage /></Suspense>} />
          <Route path={p(KHO_PATHS.baoCaoThanhPhamLoi)}      element={<Suspense><BaoCaoThanhPhamLoiPage /></Suspense>} />

          <Route path="*" element={<SimpleNotFoundPage showDevNav={showDevNav} homePath="/mh/ycmh" />} />
        </Route>
    </Routes>
  </>
);

const Root: React.FC = () => (
  <Provider store={store}>
    <Router initialEntries={[initialPath]} initialIndex={0}>
      <AppRouter />
    </Router>
  </Provider>
);

export default Root;
